use crate::registry::FilterModelDefinition;
use crate::FilterBackendKind;
use anyhow::Result;
use block_core::param::{
    bool_parameter, float_parameter, required_bool, required_f32,
    ModelParameterSchema, ParameterSet, ParameterUnit,
};
use block_core::{AudioChannelLayout, BlockProcessor, ModelAudioMode, MonoProcessor, StereoProcessor};

pub const MODEL_ID: &str = "lv2_invada_bad_hpf_mono";
pub const DISPLAY_NAME: &str = "Invada High Pass Filter (mono)";
const BRAND: &str = "invada";

const PLUGIN_URI: &str = "http://invadarecords.com/plugins/lv2/filter/hpf/mono";
const PLUGIN_DIR: &str = "invada-bad";

#[cfg(target_os = "macos")]
const PLUGIN_BINARY: &str = "inv_filter.dylib";
#[cfg(target_os = "linux")]
const PLUGIN_BINARY: &str = "inv_filter.so";
#[cfg(target_os = "windows")]
const PLUGIN_BINARY: &str = "inv_filter.dll";

// Port indices (from TTL)
const PORT_CTRL_BYPASS: usize = 0;
const PORT_CTRL_FREQ: usize = 1;
const PORT_CTRL_GAIN: usize = 2;
const PORT_CTRL_NO_CLIP: usize = 3;
const PORT_CTRL_METER_IN: usize = 4;
const PORT_CTRL_METER_OUT: usize = 5;
const PORT_AUDIO_IN_IN: usize = 6;
const PORT_AUDIO_OUT_OUT: usize = 7;
const PORT_CTRL_LAMP_DRIVE: usize = 8;

pub fn model_schema() -> ModelParameterSchema {
    ModelParameterSchema {
        effect_type: block_core::EFFECT_TYPE_FILTER.into(),
        model: MODEL_ID.into(),
        display_name: DISPLAY_NAME.into(),
        audio_mode: ModelAudioMode::DualMono,
        parameters: vec![
            bool_parameter("bypass", "Bypass", None, Some(false)),
            float_parameter("freq", "Frequency", None, Some(1000.0), 20.0, 20000.0, 10.0, ParameterUnit::Hertz),
            float_parameter("gain", "Gain", None, Some(0.0), 0.0, 12.0, 0.1, ParameterUnit::Decibels),
            bool_parameter("noclip", "Soft Clip", None, Some(false)),
        ],
    }
}

fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let freq = required_f32(params, "freq").map_err(anyhow::Error::msg)?;
    let gain = required_f32(params, "gain").map_err(anyhow::Error::msg)?;
    let noclip = required_bool(params, "noclip").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_FREQ, freq),
        (PORT_CTRL_GAIN, gain),
        (PORT_CTRL_NO_CLIP, if noclip { 1.0 } else { 0.0 }),
    ];

    match layout {
        AudioChannelLayout::Mono => {
            let processor = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT], control_ports)?;
            Ok(BlockProcessor::Mono(Box::new(processor)))
        }
        AudioChannelLayout::Stereo => {
            let left = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT], control_ports)?;
            let right = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT], control_ports)?;
            Ok(BlockProcessor::Stereo(Box::new(DualMonoProcessor { left, right })))
        }
    }
}

struct DualMonoProcessor { left: lv2::Lv2Processor, right: lv2::Lv2Processor }
impl StereoProcessor for DualMonoProcessor {
    fn process_frame(&mut self, input: [f32; 2]) -> [f32; 2] {
        [self.left.process_sample(input[0]), self.right.process_sample(input[1])]
    }
}

fn schema() -> Result<ModelParameterSchema> { Ok(model_schema()) }

pub const MODEL_DEFINITION: FilterModelDefinition = FilterModelDefinition {
    id: MODEL_ID, display_name: DISPLAY_NAME, brand: BRAND,
    backend_kind: FilterBackendKind::Lv2, schema, build,
    supported_instruments: block_core::ALL_INSTRUMENTS, knob_layout: &[],
};
